$cred = New-Object PSCredential('usr1cv8', (ConvertTo-SecureString 'usr1cv8' -AsPlainText -Force))
Invoke-Command -ComputerName 26.79.213.133 -Credential $cred -ScriptBlock {
  # Port 51401 check
  Write-Host "=== Port 51401 ==="
  Get-NetTCPConnection -LocalPort 51401 -ErrorAction SilentlyContinue | Format-Table LocalAddress, LocalPort, State, OwningProcess
  try {
    [System.Net.ServicePointManager]::ServerCertificateValidationCallback = { $true }
    $r = Invoke-WebRequest 'https://127.0.0.1:51401/api/v1/service-info' -UseBasicParsing -TimeoutSec 5
    Write-Host "ESM service-info: $($r.StatusCode) $($r.Content.Substring(0,[Math]::Min(500,$r.Content.Length)))"
  } catch { Write-Host "ESM error: $($_.Exception.Message)" }

  # POS GET with correct headers
  $tok='7c003a064e8c3885cb410168fdb4505a84a5471f'
  $url='https://online.moysklad.ru/api/posap/1.0/settings/retailstore/'
  $req = [System.Net.WebRequest]::Create($url)
  $req.Method='GET'
  $req.Headers.Add('Lognex-Pos-Auth-Token',$tok)
  $req.Headers.Add('Lognex-Pos-Auth-Cashier-Uid','manager@charisma24')
  $req.Accept='application/json'
  try {
    $resp=$req.GetResponse()
    $sr=New-Object IO.StreamReader($resp.GetResponseStream())
    $body=$sr.ReadToEnd()
    Write-Host "`n=== POS GET settings ==="
    $j = $body | ConvertFrom-Json
    Write-Host "markingEnabled=$($j.markingEnabled)"
    Write-Host "piotSettings=$($j.piotSettings | ConvertTo-Json -Compress)"
    Write-Host "sendMarksToChestnyZnakOnCloud=$($j.sendMarksToChestnyZnakOnCloud)"
  } catch { Write-Host "POS GET failed: $($_.Exception.Message)" }

  # grep logs for validation mode
  Write-Host "`n=== app.log Piot patterns ==="
  $logFiles = Get-ChildItem 'C:\Users\1\AppData\Roaming\moysklad-kassa\app.log*' | Sort-Object LastWriteTime -Descending | Select-Object -First 3
  foreach ($lf in $logFiles) {
    $matches = Select-String -Path $lf.FullName -Pattern 'PiotEsp|PiotOnline|PiotOffline|cdn\.crpt|51401|piotSettings|markingEnabled' -ErrorAction SilentlyContinue
    if ($matches) { Write-Host "--- $($lf.Name) ---"; $matches | Select-Object -Last 10 | ForEach-Object { $_.Line } }
  }

  # MoySklad process
  Write-Host "`n=== MoySklad processes ==="
  Get-Process | Where-Object { $_.Name -match 'moysklad|Касса' } | Format-Table Id, Name, StartTime
} 2>&1
